.darma-loader-darma-custom-446 {color: var(--loader-color, #db2777);
   width: 50px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px currentColor inset;
   border-radius: 50%;
   position: relative;
}
.darma-loader-darma-custom-446:before, .darma-loader-darma-custom-446:after  {
  content: "";
   position: absolute;
   top: 5px;
   left: calc(50% - 12.5px);
   box-shadow: inherit;
   width: 25px;
   aspect-ratio: 1;
   border-radius: 50%;
   transform-origin: 50% calc(100% - 5px);
   animation: darma-loader-darma-custom-446-l7 1.5s linear infinite;
}
.darma-loader-darma-custom-446:after  {
  top: calc(100% + 2px);
   transform-origin: 50% -27px;
   animation-delay: -0.75s;
}
@keyframes darma-loader-darma-custom-446-l7  {
  to  {
  transform: rotate(360deg);
}
}

